@TableName("ai_crm_opportunity") public class AiCrmOpportunity { @TableId(type = IdType.AUTO) private Long id; private Long tenantId; private Long customerId; private String opportunityNo; private String name; private String stage; private java.math.BigDecimal amount; private java.time.LocalDate expectedDate; private String ownerUser; private String status; private java.time.LocalDateTime createTime; private java.time.LocalDateTime updateTime; public Long getId(){return id;} public void setId(Long v){id=v;} public Long getTenantId(){return tenantId;} public void setTenantId(Long v){tenantId=v;} public Long getCustomerId(){return customerId;} public void setCustomerId(Long v){customerId=v;} public String getOpportunityNo(){return opportunityNo;} public void setOpportunityNo(String v){opportunityNo=v;} public String getName(){return name;} public void setName(String v){name=v;} public String getStage(){return stage;} public void setStage(String v){stage=v;} public java.math.BigDecimal getAmount(){return amount;} public void setAmount(java.math.BigDecimal v){amount=v;} public java.time.LocalDate getExpectedDate(){return expectedDate;} public void setExpectedDate(java.time.LocalDate v){expectedDate=v;} public String getOwnerUser(){return ownerUser;} public void setOwnerUser(String v){ownerUser=v;} public String getStatus(){return status;} public void setStatus(String v){status=v;} public java.time.LocalDateTime getCreateTime(){return createTime;} public void setCreateTime(java.time.LocalDateTime v){createTime=v;} public java.time.LocalDateTime getUpdateTime(){return updateTime;} public void setUpdateTime(java.time.LocalDateTime v){updateTime=v;} }
